// auto-iteration.ts 改进
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private realtimeService?: any;

  async start() {
    // 获取 Dashboard 服务（如果已启动）
    try {
      const services = getServices();
      this.realtimeService = services.realtimeService;
    } catch (e) {
      // Dashboard 未启动，忽略
    }

    // 迭代开始时通知
    await this.notifyIterationStart({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement
    });
  }

  private async notifyIterationStart(data: any) {
    if (!this.realtimeService) return;

    this.realtimeService.broadcast({
      event: 'iteration.status_changed',
      data: {
        ...data,
        timestamp: new Date().toISOString()
      }
    });
  }

  private async notifyProgress(phase: string, progress: number, message: string) {
    if (!this.realtimeService) return;

    this.realtimeService.broadcast({
      event: 'iteration.progress',
      data: { phase, progress, message, timestamp: new Date() }
    });
  }

  private async notifyAgentStatus(agentName: string, status: string, task: string) {
    if (!this.realtimeService) return;

    this.realtimeService.broadcast({
      event: 'agent.status_changed',
      data: { agentName, status, task, timestamp: new Date() }
    });
  }
}
