#### 建议 4: 添加错误恢复机制 🟠

**问题**: Agent 执行失败后无法自动恢复

**建议方案**:

```typescript
// 新建: src/error-recovery.ts
export interface RecoveryStrategy {
  maxRetries: number;
  retryDelay: number;
  fallbackAgent?: string;
}

export class ErrorRecoveryManager {
  private errorCounts: Map<string, number> = new Map();
  private strategies: Map<string, RecoveryStrategy> = new Map();

  constructor() {
    // 默认策略
    this.setDefaultStrategy({
      maxRetries: 3,
      retryDelay: 5000
    });
  }

  setDefaultStrategy(strategy: RecoveryStrategy) {
    this.strategies.set('default', strategy);
  }

  setAgentStrategy(agentName: string, strategy: RecoveryStrategy) {
    this.strategies.set(agentName, strategy);
  }

  async executeWithRecovery<T>(
    agentName: string,
    fn: () => Promise<T>
  ): Promise<T> {
    const strategy = this.strategies.get(agentName) || this.strategies.get('default')!;
    const errorKey = `${agentName}`;
    let attempt = 0;

    while (attempt < strategy.maxRetries) {
      try {
        const result = await fn();

        // 成功后重置错误计数
        this.errorCounts.delete(errorKey);
        return result;
      } catch (error) {
        attempt++;
        const currentCount = (this.errorCounts.get(errorKey) || 0) + 1;
        this.errorCounts.set(errorKey, currentCount);

        console.error(`[${agentName}] Attempt ${attempt} failed:`, error);

        if (attempt >= strategy.maxRetries) {
          // 最后一次尝试失败，执行回退
          if (strategy.fallbackAgent) {
            console.log(`[${agentName}] Falling back to ${strategy.fallbackAgent}`);
            // 实现回退逻辑
          }
          throw error;
        }

        // 等待后重试
        await this.delay(strategy.retryDelay * attempt);
      }
    }

    throw new Error(`Max retries exceeded for ${agentName}`);
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// 在 BaseAgent 中使用
export abstract class BaseAgent {
  private recoveryManager?: ErrorRecoveryManager;

  async executeWithRecovery(prompt: string): Promise<string> {
    if (!this.recoveryManager) {
      return this.executeAndCollect(prompt);
    }

    return this.recoveryManager.executeWithRecovery(
      this.role,
      () => this.executeAndCollect(prompt)
    );
  }
}
```

