// 新建: src/performance-monitor.ts
export interface AgentMetrics {
  agentName: string;
  executionCount: number;
  totalExecutionTime: number;
  averageExecutionTime: number;
  successRate: number;
  lastExecutionTime: Date;
  apiCallsCount: number;
  tokensUsed: number;
}

export class PerformanceMonitor {
  private metrics: Map<string, AgentMetrics> = new Map();
  private executionHistory: Array<any> = [];

  recordExecution(agentName: string, duration: number, success: boolean, tokens: number = 0) {
    const current = this.metrics.get(agentName) || {
      agentName,
      executionCount: 0,
      totalExecutionTime: 0,
      averageExecutionTime: 0,
      successRate: 1,
      lastExecutionTime: new Date(),
      apiCallsCount: 0,
      tokensUsed: 0
    };

    current.executionCount++;
    current.totalExecutionTime += duration;
    current.averageExecutionTime = current.totalExecutionTime / current.executionCount;
    current.lastExecutionTime = new Date();
    current.tokensUsed += tokens;

    // 计算成功率（简单版本）
    if (success) {
      current.successRate = (current.successRate * (current.executionCount - 1) + 1) / current.executionCount;
    } else {
      current.successRate = (current.successRate * (current.executionCount - 1)) / current.executionCount;
    }

    this.metrics.set(agentName, current);

    // 记录历史
    this.executionHistory.push({
      agentName,
      duration,
      success,
      tokens,
      timestamp: new Date()
    });
  }

  getMetrics(agentName: string): AgentMetrics | undefined {
    return this.metrics.get(agentName);
  }

  getAllMetrics(): AgentMetrics[] {
    return Array.from(this.metrics.values());
  }

  getPerformanceReport(): string {
    let report = '=== 性能报告 ===\n\n';

    for (const [agent, metrics] of this.metrics) {
      report += `
${agent}:
  - 执行次数: ${metrics.executionCount}
  - 平均耗时: ${metrics.averageExecutionTime.toFixed(2)}ms
  - 成功率: ${(metrics.successRate * 100).toFixed(1)}%
  - Token 使用: ${metrics.tokensUsed}
`;
    }

    return report;
  }
}
```

