// 新建: src/webhook-notifier.ts
export interface WebhookConfig {
  url: string;
  events: string[];
  headers?: Record<string, string>;
}

export class WebhookNotifier {
  private configs: WebhookConfig[] = [];

  addConfig(config: WebhookConfig) {
    this.configs.push(config);
  }

  async notify(event: string, data: any) {
    for (const config of this.configs) {
      if (!config.events.includes(event)) continue;

      try {
        await fetch(config.url, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            ...config.headers
          },
          body: JSON.stringify({
            event,
            data,
            timestamp: new Date().toISOString()
          })
        });
      } catch (error) {
        console.error(`Webhook 通知失败 (${config.url}):`, error);
      }
    }
  }
}
